var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"크윽! 역시 마스터 말대로 4종은 꽤 만만치 않은데?","JPN":"くっ！　さすがの第4種は、マスターの言うとおり手強いようだな？","ENG":"Kgh! It's just like Master said. A Category 4 isn't as easy as I thought it would be.","TWN":"咳呃！不愧是是4類侵蝕體，跟大姊說的一樣難對付呢？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"하지만 원래 쥐새끼는 궁지에 몰리면 몰릴 수록 눈에 뵈는 게 없어 진단 말이지!","JPN":"でも、ドブネズミは追い詰められれば追い詰められるほど、大胆になっていくもんなんだよ！","ENG":"But rats normally act like they have nothing to lose when they're cornered against a wall!","TWN":"但是，老鼠越是被逼入絕境，越是會拼命反抗！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"아포리아의 공격을 흡수하고 있잖아?","JPN":"アポリアの攻撃を吸収している？","ENG":"She's absorbing Aporia's attacks?","TWN":"她在吸收阿波利亞的攻擊？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"당신, 대체 누구죠? 어째서 당신이 델타 세븐의 대원복을?","JPN":"あなたはいったい？　どうしてデルタセブンの制服を？","ENG":"Hey, who are you? How come you're wearing a Delta Seven uniform?","TWN":"你，你到底是誰？為什麼穿著第七三角洲部隊的隊服？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"하고 싶은 말은 많지만!","JPN":"言いたいことはたくさんあるけどよ！","ENG":"There's a lot I want to say, but!","TWN":"雖然我也有很多話想說！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"그런 잡소리는 바쁘니까, 나중에 하자고!","JPN":"そんな雑談は、また後にしようぜ！","ENG":"Let's talk about that after we're done here, okay?","TWN":"但我現在很忙，之後再閒聊吧！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"마스터! 아직 멀었어?","JPN":"マスター！　まだなのか？","ENG":"Master! What's taking so long?","TWN":"大姊！還沒到嗎？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GUARD_EXILER_NPC_NULL","text":{"KOREA":"저길 봐! 함선이야! 하늘에서 커다란 함선이 나타났어!","JPN":"あれを見ろ！　艦船だ！　空から巨大な艦船が現れたぞ！","ENG":"Look over there! It's a ship! A huge ship appeared from the sky!","TWN":"看那邊！是艦船！天空中出現了巨型艦船！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":null,"R":{"char_id":"GUARD_EXILER_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"GUARD_EXILER_NPC_NULL","text":{"KOREA":"함선? 그렇지만 뉴 오하이오는 완파됐을 텐데?","JPN":"艦船？　しかしニューオハイオは完全に壊れたんじゃなかったのか？","ENG":"A ship? But New Ohio was blown to bits!","TWN":"艦船？但新俄亥俄已經完全被毀了啊？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"GUARD_EXILER_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"저건…… 아이기스!","JPN":"あれは……アイギス！","ENG":"That's... Aegis!","TWN":"那是……埃癸斯！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그렇다는 말은 안토노프?","JPN":"ということは、アントノフ？","ENG":"That means, it's Antonov?","TWN":"也就是說，安東諾夫來了？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"구해주는 게 벌써 두 번째군, 소령.","JPN":"助けるのは二度目だな、少佐。","ENG":"It is already the second time I have saved you, Major.","TWN":"這已經是我第二次救你了，少校。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"전 대원, 지금부터 퇴로를 확보하도록 하지. 깔려 죽고 싶지 않으면 뛰게.","JPN":"全隊員、今より退路を確保する。下敷きになって死にたくなかったら走るように。","ENG":"All units, I will secure an escape route. Run if you do not want to get crushed.","TWN":"全體隊員，現在往後退開，不想被壓死的話就動起來。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"레베카, 팔라디움 방벽을 사출한다. 자력 능력으로 낙하 위치를 보정하도록.","JPN":"レベッカ、パラディウム防壁を射出する。磁力能力で落下位置を補正してくれ。","ENG":"Rebecca, ejecting the Palladium bulwark. Calibrate the position of the drop using your magnetic force.","TWN":"蕾貝卡，我將發射守護神屏障。你用磁力來校正降落位置。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"알았으니까, 뜸들이지 말고 빨랑 던져, 마스터!!","JPN":"了解、わかったからさっさと投げてくれ、マスター！！","ENG":"Fine. Stop hesitating and throw it down already, Master!!","TWN":"知道知道，別賣關子了，快點扔下來，大姊！！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};